const crypto = require('crypto');
const input = $input.first();
const signatureHeader = input.json.headers['stripe-signature'];
const secret = $env.STRMANUALS_STRIPE_WEBHOOK_SECRET;
if (!signatureHeader) throw new Error('Missing stripe-signature header');
if (!secret) throw new Error('STRMANUALS_STRIPE_WEBHOOK_SECRET env var not set');

const rawBody = input.json.rawBody || JSON.stringify(input.json.body);
const parts = signatureHeader.split(',');
const timestamp = parts.find(p => p.startsWith('t=')).split('=')[1];
const v1 = parts.find(p => p.startsWith('v1=')).split('=')[1];
const signedPayload = `${timestamp}.${rawBody}`;
const expected = crypto.createHmac('sha256', secret).update(signedPayload).digest('hex');
if (expected !== v1) throw new Error('Invalid Stripe signature');
const now = Math.floor(Date.now() / 1000);
if (Math.abs(now - parseInt(timestamp, 10)) > 300) throw new Error('Stripe timestamp outside 5-min tolerance');

const event = typeof input.json.body === 'string' ? JSON.parse(input.json.body) : input.json.body;
return [{ json: event }];

const PRICE_TO_SLUG = {
  'price_1TVyDuFz8hgT5NXg1OKTGV1X': 'str-tax-loophole-playbook',
  'price_1TVyDvFz8hgT5NXgKaQ8ymLW': 'material-participation-survival-kit',
  'price_1TVyDvFz8hgT5NXgTgeKWgyd': 'why-bookings-down',
  'price_1TVyDwFz8hgT5NXgsjzWwmHM': 'direct-bookings-starter',
  'price_1TVyDxFz8hgT5NXgMcCqMEfx': 'permit-regulation-survival',
  'price_1TVyDyFz8hgT5NXgBdSUdZ5R': 'str-manuals-bundle'
};
const SLUG_TO_SKU = {
  'str-tax-loophole-playbook': 'MAN-TAX-01',
  'material-participation-survival-kit': 'MAN-TAX-02',
  'why-bookings-down': 'MAN-REV-01',
  'direct-bookings-starter': 'MAN-REV-02',
  'permit-regulation-survival': 'MAN-LGL-01',
  'str-manuals-bundle': 'MAN-BUNDLE-01'
};
const SLUG_TO_TITLE = {
  'str-tax-loophole-playbook': 'The STR Tax Loophole Playbook',
  'material-participation-survival-kit': 'Material Participation Survival Kit',
  'why-bookings-down': 'Why Are My Bookings Down?',
  'direct-bookings-starter': 'Direct Bookings Starter',
  'permit-regulation-survival': 'STR Permit & Regulation Survival Guide',
  'str-manuals-bundle': 'STR Manuals — All Five'
};
const COMPANION = {
  'str-tax-loophole-playbook':       { name: 'TAX-002 P&L Workbook',           url: 'https://thestrledger.com/templates/pl-single-property' },
  'material-participation-survival-kit': { name: 'Hours Log Template',         url: 'https://thestrledger.com/templates/material-participation-log' },
  'why-bookings-down':               { name: 'Break-Even Occupancy Workbook',  url: 'https://thestrledger.com/templates/break-even-occupancy' },
  'direct-bookings-starter':         { name: 'Direct-Booking Email Pack',      url: 'https://thestrledger.com/templates/direct-booking-emails' },
  'permit-regulation-survival':      { name: 'Permit Research Worksheet',      url: 'https://thestrledger.com/templates/permit-research' },
  'str-manuals-bundle':              { name: 'All five companion workbooks',   url: 'https://thestrledger.com/templates/strmanuals-bundle' }
};
const NEXT_MANUAL = {
  'str-tax-loophole-playbook':       { title: 'Material Participation Survival Kit', url: 'https://strmanuals.com/manuals/tax-02/' },
  'material-participation-survival-kit': { title: 'The STR Tax Loophole Playbook',   url: 'https://strmanuals.com/manuals/tax-01/' },
  'why-bookings-down':               { title: 'Direct Bookings Starter',             url: 'https://strmanuals.com/manuals/rev-02/' },
  'direct-bookings-starter':         { title: 'Why Are My Bookings Down?',           url: 'https://strmanuals.com/manuals/rev-01/' },
  'permit-regulation-survival':      { title: 'The STR Tax Loophole Playbook',       url: 'https://strmanuals.com/manuals/tax-01/' },
  'str-manuals-bundle':              { title: '', url: '' }
};

const all = $input.all();
const event = all[0].json;
const lineItemsResp = all.length > 1 ? all[1].json : null;
const session = event.data.object;

let priceId = null;
let slug = session.metadata && session.metadata.slug;
if (!slug && lineItemsResp && lineItemsResp.data && lineItemsResp.data[0]) {
  priceId = lineItemsResp.data[0].price && lineItemsResp.data[0].price.id;
  slug = PRICE_TO_SLUG[priceId] || null;
}
if (!slug) throw new Error('Cannot resolve strmanuals SKU from event — check line_items expansion');

const email = (session.customer_details && session.customer_details.email) || session.customer_email;
if (!email) throw new Error('No buyer email on checkout session');

const firstName = ((session.customer_details && session.customer_details.name) || '').split(' ')[0] || '';
const orderId = session.id;
const amount = session.amount_total / 100;
const currency = (session.currency || 'usd').toUpperCase();
const paidAt = new Date(session.created * 1000).toISOString();
const sku = SLUG_TO_SKU[slug];
const title = SLUG_TO_TITLE[slug];
const companion = COMPANION[slug];
const next = NEXT_MANUAL[slug];

// PDF delivery URL — Path B Option 1 (unguessable Hostinger path).
// HASH must match STRMANUALS_DOWNLOAD_HASH in STRManuals/site/.env so
// the URL points at a file that was actually copied to public_html/dl/.
// See STRManuals/docs/PDF-HOSTING.md.
const HASH = $env.STRMANUALS_DOWNLOAD_HASH;
if (!HASH) throw new Error('STRMANUALS_DOWNLOAD_HASH env var not set on n8n');
const baseUrl = $env.STRMANUALS_BASE_URL || 'https://strmanuals.com';

const isBundle = slug === 'str-manuals-bundle';
const downloadUrl = isBundle
  ? `${baseUrl}/dl/${HASH}/str-tax-loophole-playbook/v1.pdf`
  : `${baseUrl}/dl/${HASH}/${slug}/v1.pdf`;
const bundleUrls = isBundle ? [
  `${baseUrl}/dl/${HASH}/str-tax-loophole-playbook/v1.pdf`,
  `${baseUrl}/dl/${HASH}/material-participation-survival-kit/v1.pdf`,
  `${baseUrl}/dl/${HASH}/why-bookings-down/v1.pdf`,
  `${baseUrl}/dl/${HASH}/direct-bookings-starter/v1.pdf`,
  `${baseUrl}/dl/${HASH}/permit-regulation-survival/v1.pdf`
] : [];

return [{
  json: {
    email,
    first_name: firstName,
    order_id: orderId,
    amount,
    currency,
    paid_at: paidAt,
    slug,
    sku,
    manual_title: title,
    download_url: downloadUrl,
    bundle_urls: bundleUrls,
    companion_name: companion.name,
    companion_url: companion.url,
    next_manual_title: next.title,
    next_manual_url: next.url,
    is_bundle: isBundle
  }
}];
